import React, { useState, useEffect } from 'react';

import './App.css';

function App() {
  const [list, setList] = useState([]);
  const [isAdmin, setIsAdmin] = useState(false); 
  const [form, setForm] = useState({ name: '', skill: '', price: '', email: '' });

  const fetchData = async () => {
    const res = await fetch('http://localhost:5000/api/get');
    const data = await res.json();
    setList(data);
  };

  useEffect(() => { fetchData(); }, []);

  const handleAdminLogin = () => {
    const pass = prompt("Enter Admin Password:");
    if (pass === "admin123") { 
      setIsAdmin(true);
      alert("Admin Access Granted!");
    } else {
      alert("Wrong Password!");
    }
  };

  const deleteFreelancer = async (id) => {
    if (window.confirm("Delete karayche aahe ka?")) {
      await fetch(`http://localhost:5000/api/delete/${id}`, { method: 'DELETE' });
      fetchData(); 
    }
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    await fetch('http://localhost:5000/api/add', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(form)
    });
    alert("Registered Successfully!");
    setForm({ name: '', skill: '', price: '', email: '' });
    fetchData();
  };

  return (
    <div className="container">
      <header>
        <h1>Freelance Hub Marketplace</h1>
        <button className="admin-btn" onClick={isAdmin ? () => setIsAdmin(false) : handleAdminLogin}>
          {isAdmin ? "Logout Admin" : "Admin Login"}
        </button>
      </header>

      <div className="main-content">
        <div className="form-card">
          <h2>Join as Freelancer</h2>
          <form onSubmit={handleAdd}>
            <input type="text" value={form.name} placeholder="Name" required onChange={e => setForm({...form, name: e.target.value})} />
            <input type="text" value={form.skill} placeholder="Skill" required onChange={e => setForm({...form, skill: e.target.value})} />
            <input type="number" value={form.price} placeholder="Rate ($/hr)" required onChange={e => setForm({...form, price: e.target.value})} />
            <input type="email" value={form.email} placeholder="Email" required onChange={e => setForm({...form, email: e.target.value})} />
            <button type="submit" className="btn-join">Register Me</button>
          </form>
        </div>

        <div className="list-container">
          <h2>Available Talent {isAdmin && <span className="admin-badge">(Admin Mode)</span>}</h2>
          <div className="freelancer-grid">
            {list.map(f => (
              <div className="freelancer-card" key={f._id}>
                <div className="avatar">{f.name.charAt(0)}</div>
                <h3>{f.name}</h3>
                <p className="skill-tag">{f.skill}</p>
                <p><b>${f.price}/hr</b></p>
                {isAdmin && (
                  <button className="btn-delete" onClick={() => deleteFreelancer(f._id)}>Delete Profile</button>
                )}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
